1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	};
7	
8	type Item = { type: string };
9	type Step = { op: "quote"; items: Item[] };
10	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
11	
12	const basePremiumForItems = (items: Item[]): number =>
13	  items.reduce((sum, item) => sum + (BASE_PREMIUM_BY_TYPE[item.type] ?? 0), 0);
14	
15	const quotePremium = (items: Item[]): number => {
16	  const base = basePremiumForItems(items);
17	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
18	  return base + firstInsuranceSurcharge + PROCESSING_FEE;
19	};
20	
21	export const runScenario = (scenario: Scenario): unknown => {
22	  const results = scenario.steps.map((step) => ({
23	    premium: quotePremium(step.items),
24	  }));
25	  return { results };
26	};
27

